/**
 * Volunteer Video Submission Review Detail Route
 *
 * Single submission review page where volunteers can watch the video,
 * see the claimed score, verify/adjust the score, and mark as reviewed.
 */

import {
  createFileRoute,
  getRouteApi,
  Link,
  useRouter,
} from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import {
  AlertTriangle,
  ArrowLeft,
  Ban,
  Calendar,
  CheckCircle,
  CheckCircle2,
  Clock,
  ExternalLink,
  MessageSquare,
  ArrowDownUp,
  Pencil,
  ThumbsDown,
  ThumbsUp,
  Trash2,
  Trophy,
  Undo2,
  User,
} from "lucide-react"
import { useCallback, useEffect, useRef, useState } from "react"
import {
  VideoPlayerEmbed,
  supportsInteractivePlayer,
  getVideoPlatformName,
  type VideoPlayerRef,
} from "@/components/compete/video-player-embed"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Separator } from "@/components/ui/separator"
import { Textarea } from "@/components/ui/textarea"
import {
  decodeScore,
  type ParseResult,
  parseScore,
  type WorkoutScheme,
} from "@/lib/scoring"
import { cn } from "@/lib/utils"
import {
  getSchemeLabel,
  getScoreHelpText,
  getScorePlaceholder,
} from "@/components/compete/score-entry-helpers"
import {
  type EventDetails,
  getEventDetailsForVerificationFn,
  getSubmissionDetailFn,
  getVerificationLogsFn,
  type SubmissionDetail,
  type VerificationLogEntry,
  verifySubmissionScoreFn,
  deleteVerificationLogFn,
} from "@/server-fns/submission-verification-fns"
import { EnterScoreForm } from "@/components/compete/enter-score-form"
import { OrganizerVideoLinksEditor } from "@/components/compete/organizer-video-links-editor"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import {
  createReviewNoteFn,
  deleteReviewNoteFn,
  getReviewNotesForRegistrationFn,
  getWorkoutMovementsFn,
  updateReviewNoteFn,
} from "@/server-fns/review-note-fns"
import {
  getOrganizerSubmissionDetailFn,
  getSiblingSubmissionsFn,
  markSubmissionReviewedFn,
  unmarkSubmissionReviewedFn,
} from "@/server-fns/video-submission-fns"
import { getSubmissionVoteDetailsFn } from "@/server-fns/video-vote-fns"
import {
  DOWNVOTE_REASON_LABELS,
  type DownvoteReason,
} from "@/db/schemas/video-votes"
import { isSafeUrl } from "@/utils/url"

const parentRoute = getRouteApi("/compete/$slug/review")

export const Route = createFileRoute(
  "/compete/$slug/review/$eventId/$submissionId",
)({
  component: SubmissionDetailPage,
  loader: async ({ params, parentMatchPromise }) => {
    const parentMatch = await parentMatchPromise
    // The review layout route returns competition in its loader data
    const reviewData = parentMatch.loaderData
    const competition = reviewData?.competition
    if (!competition) throw new Error("Competition not found")
    const competitionId = competition.id

    // Fetch review data (required)
    const reviewResult = await getOrganizerSubmissionDetailFn({
      data: {
        submissionId: params.submissionId,
        competitionId,
      },
    })

    if (!reviewResult.submission) {
      throw new Error("Submission not found")
    }

    // If we have a score ID, fetch verification data and audit logs.
    // Otherwise still fetch event details so the no-score branch can render
    // the manual-entry form ([[lat.md/domain#Score Adjustments#Manual Score Entry]]).
    let verificationSubmission: SubmissionDetail | null = null
    let event: EventDetails | null = null
    let verificationLogs: VerificationLogEntry[] = []
    const scoreId = reviewResult.submission.scoreId
    if (scoreId) {
      try {
        const [verificationResult, logsResult] = await Promise.all([
          getSubmissionDetailFn({
            data: {
              competitionId,
              trackWorkoutId: params.eventId,
              scoreId,
            },
          }),
          getVerificationLogsFn({
            data: {
              scoreId,
              competitionId,
            },
          }),
        ])
        verificationSubmission = verificationResult.submission
        event = verificationResult.event
        verificationLogs = logsResult.logs
      } catch {
        // Verification data not available - controls won't show
      }
    } else {
      try {
        const eventResult = await getEventDetailsForVerificationFn({
          data: {
            competitionId,
            trackWorkoutId: params.eventId,
          },
        })
        event = eventResult.event
      } catch {
        // Event lookup failed — entry form won't render, falls back to placeholder
      }
    }

    // Fetch siblings for tabbed video UI
    const siblingsResult = await getSiblingSubmissionsFn({
      data: {
        submissionId: params.submissionId,
        competitionId,
      },
    })

    // Fetch review notes for ALL sibling submissions (aggregated tally)
    let allReviewNotes: Array<{
      id: string
      type: string
      content: string
      timestampSeconds: number | null
      movementId: string | null
      movementName: string | null
      videoSubmissionId: string
      createdAt: Date
      reviewer: {
        id: string
        firstName: string | null
        lastName: string | null
        avatar: string | null
      }
    }> = []

    if (reviewResult.submission.registrationId) {
      try {
        const notesResult = await getReviewNotesForRegistrationFn({
          data: {
            registrationId: reviewResult.submission.registrationId,
            trackWorkoutId: reviewResult.submission.trackWorkoutId,
            competitionId,
          },
        })
        allReviewNotes = notesResult.notes
      } catch {
        // Fall back gracefully if registration notes fetch fails
      }
    }

    // Fetch workout movements and vote details in parallel
    let workoutMovements: Array<{ id: string; name: string; type: string }> = []
    let voteDetails: {
      upvotes: number
      downvotes: number
      reasonBreakdown: Array<{ reason: string | null; count: number }>
      downvoteDetails: Array<{
        reason: string | null
        reasonDetail: string | null
        votedAt: Date
      }>
    } | null = null

    const [movementsSettled, votesSettled] = await Promise.allSettled([
      getWorkoutMovementsFn({
        data: {
          trackWorkoutId: params.eventId,
          competitionId,
        },
      }),
      getSubmissionVoteDetailsFn({
        data: {
          videoSubmissionId: params.submissionId,
          competitionId,
        },
      }),
    ])

    if (movementsSettled.status === "fulfilled") {
      workoutMovements = movementsSettled.value.movements
    }
    if (votesSettled.status === "fulfilled") {
      voteDetails = votesSettled.value
    }

    return {
      submission: reviewResult.submission,
      siblings: siblingsResult.siblings,
      siblingsTeamSize: siblingsResult.teamSize,
      siblingsRegistrationId: siblingsResult.registrationId,
      siblingsTrackWorkoutId: siblingsResult.trackWorkoutId,
      verificationSubmission,
      event,
      verificationLogs,
      allReviewNotes,
      workoutMovements,
      voteDetails,
    }
  },
})

// ============================================================================
// Verification Controls Component
// ============================================================================

interface VerificationControlsProps {
  submission: SubmissionDetail
  event: EventDetails
  competitionId: string
  trackWorkoutId: string
  logs: VerificationLogEntry[]
  submissionReviewerNotes?: string | null
}

function VerificationControls({
  submission,
  event,
  competitionId,
  trackWorkoutId,
  logs,
  submissionReviewerNotes,
}: VerificationControlsProps) {
  const router = useRouter()
  const verifyFn = useServerFn(verifySubmissionScoreFn)

  const [isPenalizing, setIsPenalizing] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const [reviewerNotes, setReviewerNotes] = useState("")

  // Adjustment form state (penalty is optional)
  const [penaltyType, setPenaltyType] = useState<"none" | "minor" | "major">(
    "none",
  )
  const [noRepCount, setNoRepCount] = useState("")
  const [penaltyScore, setPenaltyScore] = useState(
    submission.score.displayValue,
  )
  const [penaltySecondaryScore, setPenaltySecondaryScore] = useState(
    submission.score.secondaryValue !== null
      ? String(submission.score.secondaryValue)
      : "",
  )
  const [penaltyTiebreakScore, setPenaltyTiebreakScore] = useState(
    submission.score.tiebreakValue ?? "",
  )

  // Scheme config from event.workout — mirrors video-submission-form.tsx so
  // the Adjust Score form validates with the same rules athletes submit under.
  const scheme = event.workout.scheme as WorkoutScheme
  const timeCap = event.workout.timeCap
  const tiebreakScheme = event.workout.tiebreakScheme as WorkoutScheme | null

  const penaltyParseResult: ParseResult | null = penaltyScore.trim()
    ? parseScore(penaltyScore, scheme)
    : null

  // Auto-derive cap status from parsed time vs the time cap — the Status
  // picker goes away, matching the athlete submission flow.
  const penaltyStatus: "scored" | "cap" = (() => {
    if (
      penaltyParseResult?.isValid &&
      penaltyParseResult.encoded !== null &&
      scheme === "time-with-cap" &&
      timeCap
    ) {
      const capMs = timeCap * 1000
      if (penaltyParseResult.encoded >= capMs) return "cap"
    }
    return "scored"
  })()

  const showPenaltySecondaryInput =
    scheme === "time-with-cap" && penaltyStatus === "cap"

  const verificationStatus = submission.verification.status

  async function handleVerify() {
    setIsSubmitting(true)
    setError(null)
    try {
      await verifyFn({
        data: {
          competitionId,
          trackWorkoutId,
          scoreId: submission.id,
          action: "verify",
        },
      })
      await router.invalidate()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Verification failed")
    } finally {
      setIsSubmitting(false)
    }
  }

  async function handleApplyPenalty() {
    setError(null)
    if (!penaltyScore.trim()) {
      setError("Please enter an adjusted score")
      return
    }
    if (!penaltyParseResult?.isValid) {
      setError(penaltyParseResult?.error ?? "Invalid score")
      return
    }
    setIsSubmitting(true)
    try {
      await verifyFn({
        data: {
          competitionId,
          trackWorkoutId,
          scoreId: submission.id,
          action: "adjust",
          adjustedScore: penaltyScore,
          adjustedScoreStatus: penaltyStatus,
          secondaryScore:
            penaltyStatus === "cap"
              ? penaltySecondaryScore.trim() || undefined
              : undefined,
          tieBreakScore: penaltyTiebreakScore.trim() || undefined,
          reviewerNotes: reviewerNotes.trim() || undefined,
          penaltyType: penaltyType === "none" ? undefined : penaltyType,
          noRepCount: noRepCount ? Number.parseInt(noRepCount, 10) : undefined,
        },
      })
      setIsPenalizing(false)
      await router.invalidate()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Adjustment failed")
    } finally {
      setIsSubmitting(false)
    }
  }

  async function handleMarkInvalid() {
    setIsSubmitting(true)
    setError(null)
    try {
      await verifyFn({
        data: {
          competitionId,
          trackWorkoutId,
          scoreId: submission.id,
          action: "invalid",
          reviewerNotes: reviewerNotes.trim() || undefined,
        },
      })
      await router.invalidate()
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to mark invalid")
    } finally {
      setIsSubmitting(false)
    }
  }

  const statusBadge = () => {
    if (!verificationStatus) {
      return (
        <Badge variant="secondary" className="bg-gray-100 text-gray-600">
          Pending Review
        </Badge>
      )
    }
    if (verificationStatus === "verified") {
      return (
        <Badge className="bg-green-100 text-green-700 border-green-200">
          Verified
        </Badge>
      )
    }
    if (verificationStatus === "invalid") {
      return (
        <Badge className="bg-gray-100 text-gray-700 border-gray-300">
          <Ban className="h-3 w-3 mr-1" />
          Invalid
        </Badge>
      )
    }
    if (submission.verification.penaltyType) {
      return (
        <Badge
          variant="outline"
          className="bg-orange-500 text-white border-orange-500"
        >
          <AlertTriangle className="h-3 w-3 mr-1" />
          {submission.verification.penaltyType === "major"
            ? "Major Penalty"
            : "Minor Penalty"}
        </Badge>
      )
    }
    return (
      <Badge className="bg-amber-100 text-amber-700 border-amber-200">
        Adjusted
      </Badge>
    )
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Verification Controls</CardTitle>
        <CardDescription>
          Review the video and confirm or correct the athlete&apos;s claimed
          score
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Status */}
        <div className="flex items-center justify-between">
          <span className="text-sm text-muted-foreground">Status</span>
          {statusBadge()}
        </div>

        {/* Claimed score */}
        <div>
          <span className="text-sm text-muted-foreground">Athlete claimed</span>
          <p className="font-mono font-semibold">
            {submission.score.displayValue || "-"}{" "}
            {submission.score.status === "cap" && (
              <span className="text-muted-foreground text-sm font-normal">
                (capped
                {submission.score.secondaryValue !== null
                  ? `, ${submission.score.secondaryValue} reps`
                  : ""}
                )
              </span>
            )}
            {tiebreakScheme && (
              <span className="text-muted-foreground text-sm font-normal">
                {" "}
                &middot; TB: {submission.score.tiebreakValue || "—"}
              </span>
            )}
          </p>
        </div>

        {/* Penalty info display (when already penalized) */}
        {submission.verification.penaltyType && (
          <div className="rounded-md border border-orange-200 bg-orange-50 dark:bg-orange-950/20 dark:border-orange-800 p-3 space-y-1">
            <p className="text-xs font-medium text-orange-700 dark:text-orange-300">
              {submission.verification.penaltyType === "major"
                ? "Major"
                : "Minor"}{" "}
              Penalty Applied
            </p>
            <div className="flex gap-4 text-xs text-orange-600 dark:text-orange-400">
              {submission.verification.penaltyPercentage !== null && (
                <span>
                  {submission.verification.penaltyPercentage}% deduction
                </span>
              )}
              {submission.verification.noRepCount !== null && (
                <span>{submission.verification.noRepCount} no-reps</span>
              )}
            </div>
            {submissionReviewerNotes && (
              <p className="text-xs text-orange-600 dark:text-orange-400 italic mt-1">
                Note: {submissionReviewerNotes}
              </p>
            )}
          </div>
        )}

        {/* Invalid info display */}
        {verificationStatus === "invalid" && (
          <div className="rounded-md border border-gray-300 bg-gray-50 dark:bg-gray-900 dark:border-gray-700 p-3 space-y-1">
            <p className="text-xs font-medium text-gray-700 dark:text-gray-300">
              This submission has been marked invalid. The workout score has
              been zeroed.
            </p>
            {submissionReviewerNotes && (
              <p className="text-xs text-gray-600 dark:text-gray-400 italic">
                Reason: {submissionReviewerNotes}
              </p>
            )}
          </div>
        )}

        <Separator />

        {/* Action buttons */}
        {!isPenalizing && (
          <div className="grid grid-cols-2 gap-2">
            <Button
              variant={
                verificationStatus === "verified" ? "secondary" : "default"
              }
              disabled={isSubmitting}
              onClick={handleVerify}
            >
              <CheckCircle className="h-4 w-4 mr-2" />
              {verificationStatus === "verified" ? "Re-verify" : "Verify Score"}
            </Button>
            <Button
              variant="outline"
              disabled={isSubmitting}
              onClick={() => setIsPenalizing(true)}
            >
              <Pencil className="h-4 w-4 mr-2" />
              Adjust Score
            </Button>
            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button variant="outline" disabled={isSubmitting}>
                  <Ban className="h-4 w-4 mr-2" />
                  Mark Invalid
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Mark Submission Invalid</AlertDialogTitle>
                  <AlertDialogDescription>
                    This will zero the athlete&apos;s score for this workout
                    only. Their other competition scores will remain unaffected.
                    Use this for wrong movements, wrong weight/equipment, edited
                    video, or an unacceptable volume of no-reps.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <div className="space-y-2">
                  <Label htmlFor="invalid-notes" className="text-xs">
                    Reason (optional)
                  </Label>
                  <Textarea
                    id="invalid-notes"
                    value={reviewerNotes}
                    onChange={(e) => setReviewerNotes(e.target.value)}
                    placeholder="e.g. Wrong movement performed, edited video..."
                    rows={2}
                    className="text-sm"
                  />
                </div>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancel</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={handleMarkInvalid}
                    className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                  >
                    Mark Invalid
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          </div>
        )}

        {/* Adjust score form */}
        {isPenalizing && (
          <div className="space-y-3 rounded-md border border-orange-200 p-3">
            <p className="text-sm font-medium">Adjust Score</p>

            {/* Penalty type selector (optional) */}
            <div className="space-y-2">
              <Label className="text-xs">Penalty (optional)</Label>
              <RadioGroup
                value={penaltyType}
                onValueChange={(v) =>
                  setPenaltyType(v as "none" | "minor" | "major")
                }
                className="flex gap-4"
              >
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="none" id="penalty-none" />
                  <Label
                    htmlFor="penalty-none"
                    className="text-xs font-normal"
                  >
                    None
                  </Label>
                </div>
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="minor" id="penalty-minor" />
                  <Label
                    htmlFor="penalty-minor"
                    className="text-xs font-normal"
                  >
                    Minor
                  </Label>
                </div>
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="major" id="penalty-major" />
                  <Label
                    htmlFor="penalty-major"
                    className="text-xs font-normal"
                  >
                    Major
                  </Label>
                </div>
              </RadioGroup>
            </div>

            {/* No-rep count */}
            <div className="space-y-2">
              <Label htmlFor="no-rep-count" className="text-xs">
                No-rep count (optional)
              </Label>
              <Input
                id="no-rep-count"
                value={noRepCount}
                onChange={(e) => setNoRepCount(e.target.value)}
                placeholder="e.g. 12"
                type="number"
                min="0"
                className="font-mono"
              />
            </div>

            {/* Adjusted score */}
            <div className="space-y-2">
              <Label htmlFor="penalty-score" className="text-xs">
                Adjusted {getSchemeLabel(scheme)}
              </Label>
              <Input
                id="penalty-score"
                value={penaltyScore}
                onChange={(e) => setPenaltyScore(e.target.value)}
                placeholder={getScorePlaceholder(scheme)}
                className={cn(
                  "font-mono",
                  penaltyParseResult?.error &&
                    !penaltyParseResult?.isValid &&
                    "border-destructive",
                )}
              />
              {getScoreHelpText(scheme, timeCap) && (
                <p className="text-[11px] text-muted-foreground">
                  {getScoreHelpText(scheme, timeCap)}
                </p>
              )}
              {penaltyParseResult?.isValid && (
                <p className="text-[11px] text-green-600 dark:text-green-400">
                  Parsed as: {penaltyParseResult.formatted}
                  {penaltyStatus === "cap" && " (Time Cap)"}
                </p>
              )}
              {penaltyParseResult?.error && (
                <p className="text-[11px] text-destructive">
                  {penaltyParseResult.error}
                </p>
              )}
            </div>
            {penaltyStatus === "cap" && (
              <p className="text-[11px] text-amber-600 dark:text-amber-400">
                Time cap hit. Enter the reps completed at the cap below.
              </p>
            )}
            {showPenaltySecondaryInput && (
              <div className="space-y-2">
                <Label htmlFor="penalty-secondary" className="text-xs">
                  Reps at cap
                </Label>
                <Input
                  id="penalty-secondary"
                  value={penaltySecondaryScore}
                  onChange={(e) => setPenaltySecondaryScore(e.target.value)}
                  placeholder="e.g. 42"
                  type="number"
                  min="0"
                />
              </div>
            )}
            {tiebreakScheme && (
              <div className="space-y-2">
                <Label htmlFor="penalty-tiebreak" className="text-xs">
                  Tiebreak (
                  {tiebreakScheme === "time" ? "Time" : "Reps/Weight"})
                </Label>
                <Input
                  id="penalty-tiebreak"
                  value={penaltyTiebreakScore}
                  onChange={(e) => setPenaltyTiebreakScore(e.target.value)}
                  placeholder={
                    tiebreakScheme === "time" ? "e.g. 3:45" : "e.g. 100"
                  }
                  className="font-mono"
                />
              </div>
            )}

            {/* Reviewer notes */}
            <div className="space-y-2">
              <Label htmlFor="penalty-notes" className="text-xs">
                Note to athlete (optional)
              </Label>
              <Textarea
                id="penalty-notes"
                value={reviewerNotes}
                onChange={(e) => setReviewerNotes(e.target.value)}
                placeholder="Explain the adjustment..."
                rows={2}
                className="text-sm"
              />
            </div>

            <div className="flex gap-2">
              <Button
                className="flex-1"
                size="sm"
                disabled={isSubmitting || !penaltyScore.trim()}
                onClick={handleApplyPenalty}
              >
                {isSubmitting ? "Applying..." : "Adjust Score"}
              </Button>
              <Button
                variant="ghost"
                size="sm"
                disabled={isSubmitting}
                onClick={() => {
                  setIsPenalizing(false)
                  setError(null)
                }}
              >
                Cancel
              </Button>
            </div>
          </div>
        )}

        {error && <p className="text-destructive text-sm">{error}</p>}

        {/* Reviewer info */}
        {submission.verification.verifiedAt &&
          submission.verification.verifiedByName && (
            <div className="flex items-center gap-2 text-muted-foreground text-xs">
              <CheckCircle className="h-3 w-3" />
              <span>
                Reviewed by {submission.verification.verifiedByName} &middot;{" "}
                {new Intl.DateTimeFormat("en-US", {
                  dateStyle: "medium",
                }).format(new Date(submission.verification.verifiedAt))}
              </span>
            </div>
          )}

        {/* Audit Log */}
        {logs.length > 0 && (
          <>
            <Separator />
            <div className="space-y-2">
              <p className="text-sm font-medium">Audit Log</p>
              <div className="space-y-2">
                {logs.map((log) => (
                  <AuditLogEntry
                    key={log.id}
                    log={log}
                    competitionId={competitionId}
                    scoreId={submission.id}
                    trackWorkoutId={trackWorkoutId}
                    timeCap={event.workout.timeCap}
                    submissionReviewerNotes={submissionReviewerNotes}
                  />
                ))}
              </div>
            </div>
          </>
        )}
      </CardContent>
    </Card>
  )
}

// ============================================================================
// Audit Log Entry Component
// ============================================================================

function AuditLogEntry({
  log,
  competitionId,
  scoreId,
  trackWorkoutId,
  timeCap,
  submissionReviewerNotes,
}: {
  log: VerificationLogEntry
  competitionId: string
  scoreId: string
  trackWorkoutId: string
  timeCap: number | null
  submissionReviewerNotes?: string | null
}) {
  const router = useRouter()
  const deleteFn = useServerFn(deleteVerificationLogFn)
  const verifyFn = useServerFn(verifySubmissionScoreFn)
  const [isEditing, setIsEditing] = useState(false)
  const [isDeleting, setIsDeleting] = useState(false)
  const [editPenaltyType, setEditPenaltyType] = useState<
    "minor" | "major" | null
  >((log.penaltyType as "minor" | "major") ?? null)
  const [editNoRepCount, setEditNoRepCount] = useState(
    log.noRepCount?.toString() ?? "",
  )
  const [editScore, setEditScore] = useState(
    log.newScoreValue !== null && log.scheme
      ? decodeScore(log.newScoreValue, log.scheme as WorkoutScheme, {
          compact: false,
        })
      : "",
  )
  const [editStatus, setEditStatus] = useState<"scored" | "cap">(
    (log.newStatus as "scored" | "cap") ?? "scored",
  )

  async function handleDelete() {
    setIsDeleting(true)
    try {
      await deleteFn({ data: { logId: log.id, competitionId } })
      await router.invalidate()
    } catch {
      setIsDeleting(false)
    }
  }

  async function handleUpdate() {
    try {
      await verifyFn({
        data: {
          competitionId,
          trackWorkoutId,
          scoreId,
          action: "adjust",
          adjustedScore: editScore,
          adjustedScoreStatus: editStatus,
          penaltyType: editPenaltyType ?? undefined,
          noRepCount: editNoRepCount
            ? Number.parseInt(editNoRepCount, 10)
            : undefined,
        },
      })
      setIsEditing(false)
      await router.invalidate()
    } catch {
      // keep editing open on error
    }
  }

  const [isSaving, setIsSaving] = useState(false)

  if (isEditing) {
    return (
      <div className="space-y-3 rounded-md border border-orange-200 p-3">
        <p className="text-sm font-medium">Edit Penalty</p>

        {/* Penalty type selector */}
        <div className="space-y-2">
          <Label className="text-xs">Penalty type</Label>
          <RadioGroup
            value={editPenaltyType ?? "none"}
            onValueChange={(v) => {
              if (v === "none") {
                setEditPenaltyType(null)
                return
              }
              setEditPenaltyType(v as "minor" | "major")
            }}
            className="flex gap-4"
          >
            <div className="flex items-center space-x-2">
              <RadioGroupItem value="none" id={`edit-penalty-none-${log.id}`} />
              <Label
                htmlFor={`edit-penalty-none-${log.id}`}
                className="text-xs font-normal"
              >
                None
              </Label>
            </div>
            <div className="flex items-center space-x-2">
              <RadioGroupItem
                value="minor"
                id={`edit-penalty-minor-${log.id}`}
              />
              <Label
                htmlFor={`edit-penalty-minor-${log.id}`}
                className="text-xs font-normal"
              >
                Minor
              </Label>
            </div>
            <div className="flex items-center space-x-2">
              <RadioGroupItem
                value="major"
                id={`edit-penalty-major-${log.id}`}
              />
              <Label
                htmlFor={`edit-penalty-major-${log.id}`}
                className="text-xs font-normal"
              >
                Major
              </Label>
            </div>
          </RadioGroup>
        </div>

        {/* No-rep count */}
        <div className="space-y-2">
          <Label htmlFor={`edit-norep-${log.id}`} className="text-xs">
            No-rep count (optional)
          </Label>
          <Input
            id={`edit-norep-${log.id}`}
            value={editNoRepCount}
            onChange={(e) => setEditNoRepCount(e.target.value)}
            placeholder="e.g. 12"
            type="number"
            min="0"
            className="font-mono"
          />
        </div>

        {/* Adjusted score */}
        <div className="space-y-2">
          <Label htmlFor={`edit-score-${log.id}`} className="text-xs">
            Adjusted score
          </Label>
          <Input
            id={`edit-score-${log.id}`}
            value={editScore}
            onChange={(e) => setEditScore(e.target.value)}
            placeholder={timeCap ? "10:30" : "155"}
            className="font-mono"
          />
        </div>
        <div className="space-y-2">
          <Label htmlFor={`edit-status-${log.id}`} className="text-xs">
            Status
          </Label>
          <Select
            value={editStatus}
            onValueChange={(v) => setEditStatus(v as "scored" | "cap")}
          >
            <SelectTrigger id={`edit-status-${log.id}`}>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="scored">Scored</SelectItem>
              {timeCap && <SelectItem value="cap">Capped</SelectItem>}
            </SelectContent>
          </Select>
        </div>

        <div className="flex gap-2">
          <Button
            className="flex-1"
            size="sm"
            disabled={isSaving || !editScore.trim()}
            onClick={async () => {
              setIsSaving(true)
              await handleUpdate()
              setIsSaving(false)
            }}
          >
            {isSaving ? "Saving..." : "Save Changes"}
          </Button>
          <Button
            variant="ghost"
            size="sm"
            disabled={isSaving}
            onClick={() => {
              setIsEditing(false)
              setEditPenaltyType((log.penaltyType as "minor" | "major") ?? null)
              setEditNoRepCount(log.noRepCount?.toString() ?? "")
              setEditScore(
                log.newScoreValue !== null && log.scheme
                  ? decodeScore(
                      log.newScoreValue,
                      log.scheme as WorkoutScheme,
                      { compact: false },
                    )
                  : "",
              )
              setEditStatus((log.newStatus as "scored" | "cap") ?? "scored")
            }}
          >
            Cancel
          </Button>
        </div>
      </div>
    )
  }

  return (
    <div className="group rounded border px-3 py-2 text-xs space-y-1">
      <div className="flex items-center justify-between">
        <span className="font-medium capitalize">
          {log.action}
          {log.penaltyType && (
            <Badge
              variant="outline"
              className="text-[10px] px-1.5 py-0 bg-orange-500 text-white border-orange-500"
            >
              {log.penaltyType} penalty
            </Badge>
          )}
        </span>
        <div className="flex items-center gap-1">
          <span className="text-muted-foreground">
            {new Intl.DateTimeFormat("en-US", {
              dateStyle: "medium",
              timeStyle: "short",
            }).format(new Date(log.performedAt))}
          </span>
          <Button
            size="sm"
            variant="ghost"
            className="h-5 w-5 p-0 opacity-0 group-hover:opacity-100"
            onClick={() => setIsEditing(true)}
          >
            <Pencil className="h-3 w-3" />
          </Button>
          <AlertDialog>
            <AlertDialogTrigger asChild>
              <Button
                size="sm"
                variant="ghost"
                className="h-5 w-5 p-0 opacity-0 group-hover:opacity-100"
              >
                <Trash2 className="h-3 w-3" />
              </Button>
            </AlertDialogTrigger>
            <AlertDialogContent>
              <AlertDialogHeader>
                <AlertDialogTitle>Delete log entry?</AlertDialogTitle>
                <AlertDialogDescription>
                  This will permanently remove this audit log entry. This action
                  cannot be undone.
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>Cancel</AlertDialogCancel>
                <AlertDialogAction onClick={handleDelete} disabled={isDeleting}>
                  {isDeleting ? "Deleting..." : "Delete"}
                </AlertDialogAction>
              </AlertDialogFooter>
            </AlertDialogContent>
          </AlertDialog>
        </div>
      </div>
      <p className="text-muted-foreground">by {log.performedByName}</p>
      {(log.action === "adjusted" || log.action === "invalid") &&
        log.newScoreValue !== null && (
          <p className="text-muted-foreground">
            {log.originalScoreValue !== null && log.scheme
              ? decodeScore(
                  log.originalScoreValue,
                  log.scheme as WorkoutScheme,
                  { compact: false },
                )
              : "\u2014"}{" "}
            &rarr;{" "}
            {log.scheme
              ? decodeScore(log.newScoreValue, log.scheme as WorkoutScheme, {
                  compact: false,
                })
              : log.newScoreValue}
            {log.newStatus && log.newStatus !== log.originalStatus
              ? ` (${log.newStatus})`
              : ""}
          </p>
        )}
      {log.penaltyPercentage !== null && (
        <p className="text-muted-foreground">
          {log.penaltyPercentage}% deduction
          {log.noRepCount !== null && ` \u00b7 ${log.noRepCount} no-reps`}
        </p>
      )}
      {log.noRepCount !== null && log.penaltyPercentage === null && (
        <p className="text-muted-foreground">
          {log.noRepCount} no-reps
        </p>
      )}
      {submissionReviewerNotes && (
        <p className="text-muted-foreground italic">
          Note: {submissionReviewerNotes}
        </p>
      )}
    </div>
  )
}

// ============================================================================
// Review Notes Helpers & Components
// ============================================================================

function formatTimestamp(seconds: number): string {
  const mins = Math.floor(seconds / 60)
  const secs = seconds % 60
  return `${mins}:${secs.toString().padStart(2, "0")}`
}

interface ReviewNoteFormProps {
  videoSubmissionId: string
  competitionId: string
  movements: Array<{ id: string; name: string; type: string }>
  playerRef: React.RefObject<VideoPlayerRef | null>
  formTextareaRef: React.RefObject<HTMLTextAreaElement | null>
  onNoteCreated: () => void
}

function ReviewNoteForm({
  videoSubmissionId,
  competitionId,
  movements,
  playerRef,
  formTextareaRef,
  onNoteCreated,
}: ReviewNoteFormProps) {
  const createNote = useServerFn(createReviewNoteFn)
  const [noteType, setNoteType] = useState<"general" | "no-rep">("general")
  const [content, setContent] = useState("")
  const [timestampSeconds, setTimestampSeconds] = useState<number | null>(null)
  const [selectedMovementId, setSelectedMovementId] = useState<string>("")
  const [isSubmitting, setIsSubmitting] = useState(false)

  const captureTimestamp = useCallback(() => {
    if (playerRef.current) {
      const time = Math.round(playerRef.current.getCurrentTime())
      setTimestampSeconds(time)
    }
  }, [playerRef])

  const handleFocus = useCallback(() => {
    if (playerRef.current) {
      playerRef.current.pauseVideo()
      captureTimestamp()
    }
  }, [playerRef, captureTimestamp])

  const handleSubmit = async () => {
    if (!content.trim()) return
    setIsSubmitting(true)
    try {
      await createNote({
        data: {
          videoSubmissionId,
          competitionId,
          type: noteType,
          content: content.trim(),
          timestampSeconds: timestampSeconds ?? undefined,
          movementId:
            selectedMovementId && selectedMovementId !== "none"
              ? selectedMovementId
              : undefined,
        },
      })
      setContent("")
      setTimestampSeconds(null)
      onNoteCreated()
      playerRef.current?.playVideo()
    } finally {
      setIsSubmitting(false)
    }
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) {
      e.preventDefault()
      handleSubmit()
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <MessageSquare className="h-4 w-4" />
          Add Review Note
        </CardTitle>
        <CardDescription>
          Press{" "}
          <kbd className="rounded border bg-muted px-1.5 py-0.5 text-xs font-mono">
            n
          </kbd>{" "}
          to pause video and add a note
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-3">
        <div className="flex gap-1">
          <Button
            type="button"
            size="sm"
            variant={noteType === "general" ? "default" : "outline"}
            className="h-7 text-xs"
            onClick={() => setNoteType("general")}
          >
            General
          </Button>
          <Button
            type="button"
            size="sm"
            variant={noteType === "no-rep" ? "destructive" : "outline"}
            className="h-7 text-xs"
            onClick={() => setNoteType("no-rep")}
          >
            No Rep
          </Button>
        </div>
        {timestampSeconds !== null && (
          <div className="flex items-center gap-2">
            <Badge variant="outline" className="font-mono">
              {formatTimestamp(timestampSeconds)}
            </Badge>
            <button
              type="button"
              className="text-xs text-muted-foreground hover:text-foreground"
              onClick={() => setTimestampSeconds(null)}
            >
              Clear timestamp
            </button>
          </div>
        )}
        <Textarea
          ref={formTextareaRef}
          value={content}
          onChange={(e) => setContent(e.target.value)}
          onFocus={handleFocus}
          onKeyDown={handleKeyDown}
          placeholder="No rep, bad form, movement standard..."
          rows={2}
          className="text-sm"
        />
        {movements.length > 0 && (
          <div className="space-y-1">
            <Label className="text-xs">Movement (optional)</Label>
            <Select
              value={selectedMovementId}
              onValueChange={setSelectedMovementId}
            >
              <SelectTrigger className="h-8 text-sm">
                <SelectValue placeholder="Select movement..." />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="none">None</SelectItem>
                {movements.map((m) => (
                  <SelectItem key={m.id} value={m.id}>
                    {m.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        )}
        <div className="flex items-center justify-between">
          <span className="text-xs text-muted-foreground">
            {typeof navigator !== "undefined" &&
            navigator.platform?.includes("Mac")
              ? "\u2318"
              : "Ctrl"}
            +Enter to submit
          </span>
          <Button
            size="sm"
            disabled={isSubmitting || !content.trim()}
            onClick={handleSubmit}
          >
            {isSubmitting ? "Adding..." : "Add Note"}
          </Button>
        </div>
      </CardContent>
    </Card>
  )
}

interface ReviewNotesListProps {
  notes: Array<{
    id: string
    type: string
    content: string
    timestampSeconds: number | null
    movementId: string | null
    movementName: string | null
    createdAt: Date
    reviewer: {
      id: string
      firstName: string | null
      lastName: string | null
      avatar: string | null
    }
  }>
  movements: Array<{ id: string; name: string }>
  competitionId: string
  playerRef: React.RefObject<VideoPlayerRef | null>
  onNoteUpdated: () => void
}

type SortOrder = "timestamp-asc" | "timestamp-desc"
type TypeFilter = "all" | "general" | "no-rep"

function ReviewNotesList({
  notes,
  movements,
  competitionId,
  playerRef,
  onNoteUpdated,
}: ReviewNotesListProps) {
  const deleteFn = useServerFn(deleteReviewNoteFn)
  const updateFn = useServerFn(updateReviewNoteFn)
  const [deletingId, setDeletingId] = useState<string | null>(null)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [editContent, setEditContent] = useState("")
  const [editType, setEditType] = useState<"general" | "no-rep">("general")
  const [isSaving, setIsSaving] = useState(false)
  const [sortOrder, setSortOrder] = useState<SortOrder>("timestamp-asc")
  const [typeFilter, setTypeFilter] = useState<TypeFilter>("all")
  const [movementFilter, setMovementFilter] = useState<string>("all")

  const handleSeek = (seconds: number) => {
    if (playerRef.current) {
      playerRef.current.seekTo(seconds, true)
      playerRef.current.playVideo()
    }
  }

  const handleDelete = async (noteId: string) => {
    setDeletingId(noteId)
    try {
      await deleteFn({ data: { noteId, competitionId } })
      onNoteUpdated()
    } finally {
      setDeletingId(null)
    }
  }

  const startEdit = (note: ReviewNotesListProps["notes"][0]) => {
    setEditingId(note.id)
    setEditContent(note.content)
    setEditType((note.type as "general" | "no-rep") || "general")
  }

  const cancelEdit = () => {
    setEditingId(null)
    setEditContent("")
  }

  const saveEdit = async () => {
    if (!editingId || !editContent.trim()) return
    setIsSaving(true)
    try {
      await updateFn({
        data: {
          noteId: editingId,
          competitionId,
          content: editContent.trim(),
          type: editType,
        },
      })
      setEditingId(null)
      setEditContent("")
      onNoteUpdated()
    } finally {
      setIsSaving(false)
    }
  }

  const handleEditKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) {
      e.preventDefault()
      saveEdit()
    }
    if (e.key === "Escape") {
      cancelEdit()
    }
  }

  // Reset movement filter when type filter changes away from no-rep
  const effectiveMovementFilter =
    typeFilter === "no-rep" ? movementFilter : "all"

  const filteredNotes = notes.filter((note) => {
    if (typeFilter !== "all" && note.type !== typeFilter) return false
    if (
      effectiveMovementFilter !== "all" &&
      note.movementId !== effectiveMovementFilter
    )
      return false
    return true
  })

  const sortedNotes = [...filteredNotes].sort((a, b) => {
    if (a.timestampSeconds === null && b.timestampSeconds === null) return 0
    if (a.timestampSeconds === null) return 1
    if (b.timestampSeconds === null) return -1
    return sortOrder === "timestamp-asc"
      ? a.timestampSeconds - b.timestampSeconds
      : b.timestampSeconds - a.timestampSeconds
  })

  if (notes.length === 0) return null

  const toggleSortOrder = () => {
    setSortOrder(
      sortOrder === "timestamp-asc" ? "timestamp-desc" : "timestamp-asc",
    )
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle className="text-sm">
            Review Notes ({filteredNotes.length}
            {filteredNotes.length !== notes.length ? ` / ${notes.length}` : ""})
          </CardTitle>
          <Button
            variant="ghost"
            size="sm"
            className="h-7 text-xs gap-1"
            onClick={toggleSortOrder}
          >
            <ArrowDownUp className="h-3 w-3" />
            {sortOrder === "timestamp-asc" ? "Time \u2191" : "Time \u2193"}
          </Button>
        </div>
        <div className="flex flex-wrap items-center gap-2 pt-1">
          <div className="flex gap-1">
            {(["all", "general", "no-rep"] as const).map((t) => (
              <Button
                key={t}
                type="button"
                size="sm"
                variant={
                  typeFilter === t
                    ? t === "no-rep"
                      ? "destructive"
                      : "default"
                    : "outline"
                }
                className="h-6 text-xs px-2"
                onClick={() => {
                  setTypeFilter(t)
                  if (t !== "no-rep") setMovementFilter("all")
                }}
              >
                {t === "all" ? "All" : t === "general" ? "General" : "No Rep"}
              </Button>
            ))}
          </div>
          {typeFilter === "no-rep" && movements.length > 0 && (
            <Select
              value={effectiveMovementFilter}
              onValueChange={setMovementFilter}
            >
              <SelectTrigger className="h-6 text-xs w-auto min-w-[120px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All movements</SelectItem>
                {movements.map((m) => (
                  <SelectItem key={m.id} value={m.id}>
                    {m.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          )}
        </div>
      </CardHeader>
      <CardContent className="space-y-2">
        {sortedNotes.length === 0 ? (
          <p className="text-xs text-muted-foreground text-center py-2">
            No matching notes
          </p>
        ) : (
          sortedNotes.map((note) => (
            <div
              key={note.id}
              className="group rounded border px-3 py-2 text-sm space-y-1"
            >
              <div className="flex items-center justify-between gap-2">
                <div className="flex items-center gap-2">
                  {editingId === note.id ? (
                    <div className="flex gap-1">
                      <Button
                        type="button"
                        size="sm"
                        variant={editType === "general" ? "default" : "outline"}
                        className="h-5 text-xs px-1.5"
                        onClick={() => setEditType("general")}
                      >
                        General
                      </Button>
                      <Button
                        type="button"
                        size="sm"
                        variant={
                          editType === "no-rep" ? "destructive" : "outline"
                        }
                        className="h-5 text-xs px-1.5"
                        onClick={() => setEditType("no-rep")}
                      >
                        No Rep
                      </Button>
                    </div>
                  ) : (
                    <>
                      {note.type === "no-rep" && (
                        <Badge
                          variant="outline"
                          className="bg-orange-500 text-white border-orange-500 text-xs"
                        >
                          No Rep
                        </Badge>
                      )}
                      {note.timestampSeconds !== null && (
                        <button
                          type="button"
                          onClick={() => handleSeek(note.timestampSeconds!)}
                          className="font-mono text-xs text-primary hover:underline"
                        >
                          {formatTimestamp(note.timestampSeconds)}
                        </button>
                      )}
                      {note.movementName && (
                        <Badge variant="secondary" className="text-xs">
                          {note.movementName}
                        </Badge>
                      )}
                    </>
                  )}
                </div>
                {editingId !== note.id && (
                  <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6"
                      onClick={() => startEdit(note)}
                    >
                      <Pencil className="h-3 w-3" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6"
                      disabled={deletingId === note.id}
                      onClick={() => handleDelete(note.id)}
                    >
                      <Trash2 className="h-3 w-3" />
                    </Button>
                  </div>
                )}
              </div>
              {editingId === note.id ? (
                <div className="space-y-2">
                  <Textarea
                    value={editContent}
                    onChange={(e) => setEditContent(e.target.value)}
                    onKeyDown={handleEditKeyDown}
                    rows={2}
                    className="text-sm"
                    autoFocus
                  />
                  <div className="flex items-center justify-end gap-2">
                    <Button
                      size="sm"
                      variant="ghost"
                      className="h-7 text-xs"
                      onClick={cancelEdit}
                    >
                      Cancel
                    </Button>
                    <Button
                      size="sm"
                      className="h-7 text-xs"
                      disabled={isSaving || !editContent.trim()}
                      onClick={saveEdit}
                    >
                      {isSaving ? "Saving..." : "Save"}
                    </Button>
                  </div>
                </div>
              ) : (
                <>
                  <p className="text-sm">{note.content}</p>
                  <p className="text-xs text-muted-foreground">
                    {note.reviewer.firstName} {note.reviewer.lastName}
                  </p>
                </>
              )}
            </div>
          ))
        )}
      </CardContent>
    </Card>
  )
}

interface MovementTallyCardProps {
  notes: Array<{
    type: string
    movementId: string | null
    movementName: string | null
  }>
}

function MovementTallyCard({ notes }: MovementTallyCardProps) {
  const noRepNotes = notes.filter((n) => n.type === "no-rep")
  const noRepCount = noRepNotes.length

  const tallies = new Map<string, { name: string; count: number }>()
  for (const note of noRepNotes) {
    if (note.movementId && note.movementName) {
      const existing = tallies.get(note.movementId)
      if (existing) {
        existing.count++
      } else {
        tallies.set(note.movementId, { name: note.movementName, count: 1 })
      }
    }
  }

  if (notes.length === 0) return null

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-sm flex items-center gap-2">
          <MessageSquare className="h-4 w-4" />
          Review Summary
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-2">
