/**
 * Get platform display name for a video URL
 */
export function getVideoPlatformName(url: string): string | null {
  const parsed = parseVideoUrl(url)
  if (!parsed) return null
  switch (parsed.platform) {
    case "youtube":
      return "YouTube"
    case "vimeo":
      return "Vimeo"
    case "wodproof":
      return "WodProof"
  }
}

