// ── Common player interface ──────────────────────────────────────────

export interface VideoPlayerRef {
  pauseVideo: () => void
  playVideo: () => void
  getCurrentTime: () => number
  seekTo: (seconds: number, allowSeekAhead?: boolean) => void
  platform: VideoPlatform
}

