function YouTubePlayer({
  videoId,
  className,
  onPlayerReady,
}: {
  videoId: string
  className?: string
  onPlayerReady?: (player: VideoPlayerRef) => void
}) {
  const reactId = useId()
  const elementId = `yt-player-${reactId.replace(/:/g, "-")}`
  const playerRef = useRef<YT.Player | null>(null)
  const onReadyRef = useRef(onPlayerReady)
  onReadyRef.current = onPlayerReady

  useEffect(() => {
    let destroyed = false

    loadYouTubeApi().then(() => {
      if (destroyed) return
      playerRef.current = new YT.Player(elementId, {
        videoId,
        playerVars: { rel: 0, modestbranding: 1, enablejsapi: 1 },
        events: {
          onReady: (event) => {
            if (destroyed) return
            const p = event.target
            const ref: VideoPlayerRef = {
              platform: "youtube",
              pauseVideo: () => p.pauseVideo(),
              playVideo: () => p.playVideo(),
              getCurrentTime: () => p.getCurrentTime(),
              seekTo: (seconds, allowSeekAhead) =>
                p.seekTo(seconds, allowSeekAhead),
            }
            onReadyRef.current?.(ref)
          },
        },
      })
    })

    return () => {
      destroyed = true
      playerRef.current?.destroy()
      playerRef.current = null
    }
  }, [videoId, elementId])

  return (
    <div
      className={cn(
        "relative aspect-video w-full overflow-hidden rounded-lg bg-black",
        className,
      )}
    >
      <div id={elementId} className="absolute inset-0 h-full w-full" />
    </div>
  )
}

// ── Vimeo Player ─────────────────────────────────────────────────────

function VimeoPlayer({
  videoId,
  privacyHash,
  className,
  onPlayerReady,
}: {
  videoId: string
  privacyHash?: string
  className?: string
  onPlayerReady?: (player: VideoPlayerRef) => void
}) {
  const reactId = useId()
  const containerId = `vimeo-player-${reactId.replace(/:/g, "-")}`
  const playerRef = useRef<InstanceType<
    typeof import("@vimeo/player").default
  > | null>(null)
  const onReadyRef = useRef(onPlayerReady)
  onReadyRef.current = onPlayerReady

  useEffect(() => {
    let destroyed = false

    import("@vimeo/player").then(({ default: VimeoPlayerClass }) => {
      if (destroyed) return

      const container = document.getElementById(containerId)
      if (!container) return

      const options: Record<string, unknown> = {
        id: Number(videoId),
        responsive: true,
      }
      if (privacyHash) {
        options.h = privacyHash
      }

      const player = new VimeoPlayerClass(container, options)
      playerRef.current = player

      player.ready().then(() => {
        if (destroyed) return

        // Cache for synchronous getCurrentTime calls
        let cachedTime = 0
        player.on("timeupdate", (data: { seconds: number }) => {
          cachedTime = data.seconds
        })

        const ref: VideoPlayerRef = {
          platform: "vimeo",
          pauseVideo: () => {
            player.pause()
          },
          playVideo: () => {
            player.play()
          },
          getCurrentTime: () => cachedTime,
          seekTo: (seconds) => {
            player.setCurrentTime(seconds)
          },
        }
        onReadyRef.current?.(ref)
      })
    })

    return () => {
      destroyed = true
      playerRef.current?.destroy()
      playerRef.current = null
    }
  }, [videoId, privacyHash, containerId])

  return (
    <div
      className={cn(
        "relative aspect-video w-full overflow-hidden rounded-lg bg-black",
        className,
      )}
    >
      <div id={containerId} className="absolute inset-0 h-full w-full" />
    </div>
  )
}

// ── WodProof Player ─────────────────────────────────────────────────

function WodProofPlayer({
  videoId,
  originalUrl,
  className,
  onPlayerReady,
}: {
  videoId: string
  originalUrl: string
  className?: string
  onPlayerReady?: (player: VideoPlayerRef) => void
}) {
  const videoRef = useRef<HTMLVideoElement>(null)
  const onReadyRef = useRef(onPlayerReady)
  onReadyRef.current = onPlayerReady
  const [error, setError] = useState(false)

  useEffect(() => {
    const video = videoRef.current
    if (!video) return

    const handleCanPlay = () => {
      const ref: VideoPlayerRef = {
        platform: "wodproof",
        pauseVideo: () => video.pause(),
        playVideo: () => {
          video.play()
        },
        getCurrentTime: () => video.currentTime,
        seekTo: (seconds) => {
          video.currentTime = seconds
        },
      }
      onReadyRef.current?.(ref)
    }

    video.addEventListener("canplay", handleCanPlay)
    return () => video.removeEventListener("canplay", handleCanPlay)
  }, [])

  if (error) {
    return (
      <div
        className={cn(
          "relative aspect-video w-full overflow-hidden rounded-lg bg-muted flex flex-col items-center justify-center gap-3 p-4",
          className,
        )}
      >
        <span className="text-sm text-muted-foreground">
          Video could not be loaded
        </span>
        <a
          href={isSafeUrl(originalUrl) ? originalUrl : "#"}
          target="_blank"
          rel="noopener noreferrer"
          className="inline-flex items-center gap-2 text-primary hover:underline text-sm"
        >
          <ExternalLink className="h-4 w-4" />
          Open in WodProof
        </a>
      </div>
    )
  }

  return (
    <div
      className={cn(
        "relative aspect-video w-full overflow-hidden rounded-lg bg-black",
        className,
      )}
    >
      {/* biome-ignore lint/a11y/useMediaCaption: workout videos don't have captions */}
      <video
        ref={videoRef}
        src={getWodProofVideoUrl(videoId)}
        controls
        playsInline
        className="absolute inset-0 h-full w-full"
        onError={() => setError(true)}
      />
    </div>
  )
}

// ── Unified component ────────────────────────────────────────────────

export function VideoPlayerEmbed({
  url,
  className,
  onPlayerReady,
}: VideoPlayerEmbedProps) {
  const parsed = parseVideoUrl(url)

  // No parse result or platform without embed support
  if (!parsed || !parsed.supportsEmbed) {
    return (
      <div
        className={cn(
          "relative aspect-video w-full overflow-hidden rounded-lg bg-muted flex flex-col items-center justify-center gap-3 p-4",
          className,
        )}
      >
        <a
          href={isSafeUrl(url) ? url : "#"}
          target="_blank"
          rel="noopener noreferrer"
          className="inline-flex items-center gap-2 text-primary hover:underline text-sm"
        >
          <ExternalLink className="h-4 w-4" />
          Open video in new tab
        </a>
      </div>
    )
  }

  switch (parsed.platform) {
    case "youtube":
      return (
        <YouTubePlayer
          videoId={parsed.videoId}
          className={className}
          onPlayerReady={onPlayerReady}
        />
      )
    case "vimeo":
      return (
        <VimeoPlayer
          videoId={parsed.videoId}
          privacyHash={parsed.privacyHash}
          className={className}
          onPlayerReady={onPlayerReady}
        />
      )
    case "wodproof":
      return (
        <WodProofPlayer
          videoId={parsed.videoId}
          originalUrl={parsed.originalUrl}
          className={className}
          onPlayerReady={onPlayerReady}
        />
      )
  }
}

